1068:                                               connection_manager_.config_->tracingStats());
1069:   }
1070: 
1071:   uint64_t response_code = Utility::getResponseStatus(headers);
1072:   filter_manager_.streamInfo().setResponseCode(response_code);
1073: 
1074:   if (filter_manager_.streamInfo().healthCheck()) {
1075:     return;
1076:   }
1077: 
1078:   // No response is sent back downstream for internal redirects, so don't charge downstream stats.
1079:   const absl::optional<std::string>& response_code_details =
1080:       filter_manager_.streamInfo().responseCodeDetails();
1081:   if (response_code_details.has_value() &&
1082:       response_code_details == Envoy::StreamInfo::ResponseCodeDetails::get().InternalRedirect) {
1083:     return;
1084:   }
1085: 
1086:   connection_manager_.stats_.named_.downstream_rq_completed_.inc();
1087:   connection_manager_.listener_stats_.downstream_rq_completed_.inc();
1088:   if (CodeUtility::is1xx(response_code)) {
1089:     connection_manager_.stats_.named_.downstream_rq_1xx_.inc();
1090:     connection_manager_.listener_stats_.downstream_rq_1xx_.inc();
1091:   } else if (CodeUtility::is2xx(response_code)) {
1092:     connection_manager_.stats_.named_.downstream_rq_2xx_.inc();
1093:     connection_manager_.listener_stats_.downstream_rq_2xx_.inc();
1094:   } else if (CodeUtility::is3xx(response_code)) {
1095:     connection_manager_.stats_.named_.downstream_rq_3xx_.inc();
1096:     connection_manager_.listener_stats_.downstream_rq_3xx_.inc();
1097:   } else if (CodeUtility::is4xx(response_code)) {
1098:     connection_manager_.stats_.named_.downstream_rq_4xx_.inc();
1099:     connection_manager_.listener_stats_.downstream_rq_4xx_.inc();
1100:   } else if (CodeUtility::is5xx(response_code)) {
1101:     connection_manager_.stats_.named_.downstream_rq_5xx_.inc();
1102:     connection_manager_.listener_stats_.downstream_rq_5xx_.inc();
