1130:   ASSERT(active_span_ != nullptr);
1131:   const Router::Decorator* decorater = route_decorator_;
1132: 
1133:   // If a decorator has been defined, apply it to the active span.
1134:   absl::string_view decorated_operation;
1135:   if (decorater != nullptr) {
1136:     decorated_operation = decorater->getOperation();
1137: 
1138:     decorater->apply(*active_span_);
1139:     state_.decorated_propagate_ = decorater->propagate();
1140:   }
1141: 
1142:   if (connection_manager_tracing_config_->operation_name_ == Tracing::OperationName::Egress) {
1143:     // For egress (outbound) requests, pass the decorator's operation name (if defined and
1144:     // propagation enabled) as a request header to enable the receiving service to use it in its
1145:     // server span.
1146:     if (!decorated_operation.empty() && state_.decorated_propagate_) {
1147:       headers.setEnvoyDecoratorOperation(decorated_operation);
1148:     }
1149:   } else {
1150:     absl::string_view req_operation_override = headers.getEnvoyDecoratorOperationValue();
1151: 
1152:     // For ingress (inbound) requests, if a decorator operation name has been provided, it
1153:     // should be used to override the active span's operation.
1154:     if (!req_operation_override.empty()) {
1155:       active_span_->setOperation(req_operation_override);
1156: 
1157:       // Set the decorator operation as overridden to avoid propagating the route decorator
1158:       // operation to the client when the setResponseDecorator() is called.
1159:       state_.decorator_overriden_ = true;
1160:     }
1161:     // Remove header so not propagated to service
1162:     headers.removeEnvoyDecoratorOperation();
1163:   }
1164: }
