400: RequestDecoder& ConnectionManagerImpl::newStream(ResponseEncoder& response_encoder,
401:                                                  bool is_internally_created) {
402:   TRACE_EVENT("core", "ConnectionManagerImpl::newStream");
403:   if (connection_idle_timer_) {
404:     connection_idle_timer_->disableTimer();
405:   }
406: 
407:   ENVOY_CONN_LOG(debug, "new stream", read_callbacks_->connection());
408: 
409:   Buffer::BufferMemoryAccountSharedPtr downstream_stream_account =
410:       response_encoder.getStream().account();
411: 
412:   if (downstream_stream_account == nullptr) {
413:     // Create account, wiring the stream to use it for tracking bytes.
414:     // If tracking is disabled, the wiring becomes a NOP.
415:     auto& buffer_factory = dispatcher_->getWatermarkFactory();
416:     downstream_stream_account = buffer_factory.createAccount(response_encoder.getStream());
417:     response_encoder.getStream().setAccount(downstream_stream_account);
418:   }
419: 
420:   auto new_stream = std::make_unique<ActiveStream>(
421:       *this, response_encoder.getStream().bufferLimit(), std::move(downstream_stream_account));
422: 
423:   accumulated_requests_++;
424:   if (config_->maxRequestsPerConnection() > 0 &&
425:       accumulated_requests_ >= config_->maxRequestsPerConnection()) {
426:     if (codec_->protocol() < Protocol::Http2) {
427:       new_stream->filter_manager_.streamInfo().setShouldDrainConnectionUponCompletion(true);
428:       // Prevent erroneous debug log of closing due to incoming connection close header.
429:       drain_state_ = DrainState::Closing;
430:     } else if (drain_state_ == DrainState::NotDraining) {
431:       startDrainSequence();
432:     }
433:     ENVOY_CONN_LOG(debug, "max requests per connection reached", read_callbacks_->connection());
434:     stats_.named_.downstream_cx_max_requests_reached_.inc();
435:   }
436: 
437:   if (soft_drain_http1_) {
438:     new_stream->filter_manager_.streamInfo().setShouldDrainConnectionUponCompletion(true);
439:     // Prevent erroneous debug log of closing due to incoming connection close header.
440:     drain_state_ = DrainState::Closing;
441:   }
442: 
443:   new_stream->state_.is_internally_created_ = is_internally_created;
444:   new_stream->response_encoder_ = &response_encoder;
445:   new_stream->response_encoder_->getStream().addCallbacks(*new_stream);
446:   new_stream->response_encoder_->getStream().registerCodecEventCallbacks(new_stream.get());
447:   if (config_->streamFlushTimeout().has_value()) {
448:     new_stream->response_encoder_->getStream().setFlushTimeout(
449:         config_->streamFlushTimeout().value());
450:   } else {
451:     new_stream->response_encoder_->getStream().setFlushTimeout(config_->streamIdleTimeout());
452:   }
453:   new_stream->streamInfo().setDownstreamBytesMeter(response_encoder.getStream().bytesMeter());
454:   new_stream->streamInfo().setCodecStreamId(response_encoder.getStream().codecStreamId());
455:   // If the network connection is backed up, the stream should be made aware of it on creation.
456:   // Both HTTP/1.x and HTTP/2 codecs handle this in StreamCallbackHelper::addCallbacksHelper.
457:   ASSERT(read_callbacks_->connection().aboveHighWatermark() == false ||
458:          new_stream->filter_manager_.aboveHighWatermark());
459:   LinkedList::moveIntoList(std::move(new_stream), streams_);
460:   return **streams_.begin();
461: }
