1810:   }
1811: 
1812:   ASSERT(cached_route_.has_value());
1813: 
1814:   // NOTE: if the trace reason have been encoded into the request id then the trace reason may
1815:   // not be updated. That means we may cannot to force a traced request to be untraced by the
1816:   // refreshing.
1817:   const auto trace_reason = ConnectionManagerUtility::mutateTracingRequestHeader(
1818:       *request_headers_, connection_manager_.runtime_, *connection_manager_.config_,
1819:       cached_route_.value().get());
1820:   filter_manager_.streamInfo().setTraceReason(trace_reason);
1821:   const Tracing::Decision tracing_decision =
1822:       Tracing::TracerUtility::shouldTraceRequest(filter_manager_.streamInfo());
1823:   if (active_span_->useLocalDecision()) {
1824:     active_span_->setSampled(tracing_decision.traced);
