1827:   if (hasCachedRoute()) {
1828:     route_decorator_ = cached_route_.value()->decorator();
1829:     route_tracing_ = cached_route_.value()->tracingConfig();
1830:   }
1831:   if (!operationNameFormatter(*connection_manager_tracing_config_, route_tracing_)) {
1832:     // Only set decorator when there is no operation name formatter configured at either
1833:     // the HCM level or the route level.
1834:     setRequestDecorator(*request_headers_);
