1866: void ConnectionManagerImpl::ActiveStream::encode1xxHeaders(ResponseHeaderMap& response_headers) {
1867:   ENVOY_EXECUTION_SCOPE(trackedStream(), active_span_.get());
1868:   // Strip the T-E headers etc. Defer other header additions as well as drain-close logic to the
1869:   // continuation headers.
1870:   ConnectionManagerUtility::mutateResponseHeaders(
1871:       response_headers, request_headers_.get(), *connection_manager_.config_, EMPTY_STRING,
1872:       filter_manager_.streamInfo(), connection_manager_.proxy_name_,
1873:       connection_manager_.clear_hop_by_hop_response_headers_);
1874: 
1875:   // Count both the 1xx and follow-up response code in stats.
1876:   chargeStats(response_headers);
1877: 
1878:   ENVOY_STREAM_LOG(debug, "encoding 1xx continue headers via codec:\n{}", *this, response_headers);
1879: 
1880:   // Now actually encode via the codec.
1881:   response_encoder_->encode1xxHeaders(response_headers);
1882: }
