1884: void ConnectionManagerImpl::ActiveStream::encodeHeaders(ResponseHeaderMap& headers,
1885:                                                         bool end_stream) {
1886:   ENVOY_EXECUTION_SCOPE(trackedStream(), active_span_.get());
1887:   // Base headers.
1888: 
1889:   // We want to preserve the original date header, but we add a date header if it is absent
1890:   if (!headers.Date()) {
1891:     connection_manager_.config_->dateProvider().setDateHeader(headers);
1892:   }
1893: 
1894:   // Following setReference() is safe because serverName() is constant for the life of the
1895:   // listener.
1896:   const auto transformation = connection_manager_.config_->serverHeaderTransformation();
1897:   if (transformation == ConnectionManagerConfig::HttpConnectionManagerProto::OVERWRITE ||
1898:       (transformation == ConnectionManagerConfig::HttpConnectionManagerProto::APPEND_IF_ABSENT &&
1899:        headers.Server() == nullptr)) {
1900:     headers.setReferenceServer(connection_manager_.config_->serverName());
1901:   }
1902:   ConnectionManagerUtility::mutateResponseHeaders(
1903:       headers, request_headers_.get(), *connection_manager_.config_,
1904:       connection_manager_.config_->via(), filter_manager_.streamInfo(),
1905:       connection_manager_.proxy_name_, connection_manager_.clear_hop_by_hop_response_headers_);
1906: 
1907:   bool drain_connection_due_to_overload = false;
1908:   if (connection_manager_.drain_state_ == DrainState::NotDraining &&
1909:       connection_manager_.random_generator_.bernoulli(
1910:           connection_manager_.overload_disable_keepalive_ref_.value())) {
1911:     ENVOY_STREAM_LOG(debug, "disabling keepalive due to envoy overload", *this);
1912:     drain_connection_due_to_overload = true;
1913:     connection_manager_.stats_.named_.downstream_cx_overload_disable_keepalive_.inc();
1914:   }
1915: 
1916:   // If we're an inbound listener, then we should drain even if the drain direction is inbound only.
1917:   // If not, then we only drain if the drain direction is all.
1918:   Network::DrainDirection drain_scope =
1919:       connection_manager_.direction_ == envoy::config::core::v3::TrafficDirection::INBOUND
1920:           ? Network::DrainDirection::InboundOnly
1921:           : Network::DrainDirection::All;
1922: 
1923:   // See if we want to drain/close the connection. Send the go away frame prior to encoding the
1924:   // header block. Only drain if the drain direction is not inbound only or the connection is
1925:   // inbound.
1926:   if (connection_manager_.drain_state_ == DrainState::NotDraining &&
1927:       (connection_manager_.drain_close_.drainClose(drain_scope) ||
1928:        drain_connection_due_to_overload)) {
1929: 
1930:     // This doesn't really do anything for HTTP/1.1 other then give the connection another boost
1931:     // of time to race with incoming requests. For HTTP/2 connections, send a GOAWAY frame to
1932:     // prevent any new streams.
1933:     connection_manager_.startDrainSequence();
1934:     connection_manager_.stats_.named_.downstream_cx_drain_close_.inc();
1935:     ENVOY_STREAM_LOG(debug, "drain closing connection", *this);
1936:   }
1937: 
1938:   if (connection_manager_.codec_->protocol() == Protocol::Http10) {
1939:     // As HTTP/1.0 and below can not do chunked encoding, if there is no content
1940:     // length the response will be framed by connection close.
1941:     if (!headers.ContentLength()) {
1942:       filter_manager_.streamInfo().setShouldDrainConnectionUponCompletion(true);
1943:     }
1944:     // If the request came with a keep-alive and no other factor resulted in a
1945:     // connection close header, send an explicit keep-alive header.
1946:     if (!filter_manager_.streamInfo().shouldDrainConnectionUponCompletion()) {
1947:       headers.setConnection(Headers::get().ConnectionValues.KeepAlive);
1948:     }
1949:   }
1950: 
1951:   if (connection_manager_.drain_state_ == DrainState::NotDraining &&
1952:       filter_manager_.streamInfo().shouldDrainConnectionUponCompletion()) {
1953:     ENVOY_STREAM_LOG(debug, "closing connection due to connection close header", *this);
1954:     // For HTTP/2 and HTTP/3, send GOAWAY and allow current stream to complete.
1955:     // For HTTP/1.1, go directly to Closing (Connection: close header will be added below).
1956:     if (connection_manager_.codec_->protocol() >= Protocol::Http2) {
1957:       connection_manager_.startDrainSequence();
1958:     } else {
1959:       connection_manager_.drain_state_ = DrainState::Closing;
1960:     }
1961:   }
1962: 
1963:   // If we are destroying a stream before remote is complete and the connection does not support
1964:   // multiplexing, we should disconnect since we don't want to wait around for the request to
1965:   // finish.
1966:   if (!filter_manager_.hasLastDownstreamByteReceived()) {
1967:     if (connection_manager_.codec_->protocol() < Protocol::Http2) {
1968:       connection_manager_.drain_state_ = DrainState::Closing;
1969:     }
1970: 
1971:     connection_manager_.stats_.named_.downstream_rq_response_before_rq_complete_.inc();
1972:   }
1973: 
1974:   if (Utility::isUpgrade(headers) ||
1975:       HeaderUtility::isConnectResponse(request_headers_.get(), *responseHeaders())) {
1976:     state_.is_tunneling_ = true;
1977:   }
1978: 
1979:   // Block route cache if the response headers is received and processed. Because after this
1980:   // point, the cached route should never be updated or refreshed.
1981:   blockRouteCache();
1982: 
1983:   if (connection_manager_.drain_state_ != DrainState::NotDraining &&
1984:       connection_manager_.codec_->protocol() < Protocol::Http2) {
1985:     // If the connection manager is draining send "Connection: Close" on HTTP/1.1 connections.
1986:     // Do not do this for H2 (which drains via GOAWAY) or Upgrade or CONNECT (as the
1987:     // payload is no longer HTTP/1.1)
1988:     if (!state_.is_tunneling_) {
1989:       headers.setReferenceConnection(Headers::get().ConnectionValues.Close);
1990:     }
1991:   }
1992: 
1993:   if (active_span_ != nullptr) {
1994:     ASSERT(connection_manager_tracing_config_.has_value());
1995:     if (!operationNameFormatter(*connection_manager_tracing_config_, route_tracing_)) {
1996:       // Only apply decorator if there is no operation name formatter configured at either
1997:       // the HCM level or the route level.
1998:       setResponseDecorator(headers);
1999:     }
2000:   }
