1690: void ConnectionManagerImpl::ActiveStream::refreshDurationTimeout() {
1691:   if (!hasCachedRoute() || !request_headers_) {
1692:     return;
1693:   }
1694:   const Router::RouteEntry* route = cached_route_.value()->routeEntry();
1695:   if (route == nullptr) {
1696:     return;
1697:   }
1698:   auto grpc_timeout = Grpc::Common::getGrpcTimeout(*request_headers_);
1699:   std::chrono::milliseconds timeout;
1700:   bool disable_timer = false;
1701: 
1702:   if (!grpc_timeout || !route->grpcTimeoutHeaderMax()) {
1703:     // Either there is no grpc-timeout header or special timeouts for it are not
1704:     // configured. Use stream duration.
1705:     if (route->maxStreamDuration()) {
1706:       timeout = route->maxStreamDuration().value();
1707:       if (timeout == std::chrono::milliseconds(0)) {
1708:         // Explicitly configured 0 means no timeout.
1709:         disable_timer = true;
1710:       }
1711:     } else {
1712:       // Fall back to HCM config. If no HCM duration limit exists, disable
1713:       // timers set by any prior route configuration.
1714:       const auto max_stream_duration = connection_manager_.config_->maxStreamDuration();
1715:       if (max_stream_duration.has_value() && max_stream_duration.value().count()) {
1716:         timeout = max_stream_duration.value();
1717:       } else {
1718:         disable_timer = true;
1719:       }
1720:     }
1721:   } else {
1722:     // Start with the timeout equal to the gRPC timeout header.
1723:     timeout = grpc_timeout.value();
1724:     // If there's a valid cap, apply it.
1725:     if (timeout > route->grpcTimeoutHeaderMax().value() &&
1726:         route->grpcTimeoutHeaderMax().value() != std::chrono::milliseconds(0)) {
1727:       timeout = route->grpcTimeoutHeaderMax().value();
1728:     }
1729: 
1730:     // Apply the configured offset.
1731:     if (timeout != std::chrono::milliseconds(0) && route->grpcTimeoutHeaderOffset()) {
1732:       const auto offset = route->grpcTimeoutHeaderOffset().value();
1733:       if (offset < timeout) {
1734:         timeout -= offset;
1735:       } else {
1736:         timeout = std::chrono::milliseconds(0);
1737:       }
1738:     }
1739:   }
1740: 
1741:   // Disable any existing timer if configured to do so.
1742:   if (disable_timer) {
1743:     if (max_stream_duration_timer_) {
1744:       max_stream_duration_timer_->disableTimer();
1745:       if (route->usingNewTimeouts() && Grpc::Common::isGrpcRequestHeaders(*request_headers_)) {
1746:         request_headers_->removeGrpcTimeout();
1747:       }
1748:     }
1749:     return;
1750:   }
